import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"盾之勇者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/盾之勇者.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/盾之勇者.md"}'),o={name:"4.资源分区/1.血统与训练/6.一次性血统/盾之勇者.md"};function p(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"盾之勇者",tabindex:"-1"},[n("盾之勇者 "),r("a",{class:"header-anchor",href:"#盾之勇者","aria-label":'Permalink to "盾之勇者"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"汹涌疾风023")])])],-1),s('<h1 id="盾之勇者-1" tabindex="-1">盾之勇者 <a class="header-anchor" href="#盾之勇者-1" aria-label="Permalink to &quot;盾之勇者&quot;">​</a></h1><p>盾之勇者</p><p>C+1200<br> 一次性训练<br> 原典：盾之勇者成名录<br> 受到召唤而来抵御浪潮的四圣勇者之一，尽管蒙受了不白之冤，却依然从困境中站起而成为人类的支柱。</p><p>能量池：魔力（关键属性为耐力+感知）<br> 特性：盾牌专擅、背包栏位、能力解放、等级提升<br> 【盾牌专擅】：强化者无法使用任何除了盾以外的武器。<br> 每场景一次，强化者在使用盾牌时，可以自由动作将任意点武器伤害在一场景内转化为在格挡时生效的格挡防御。<br> 【背包栏位】：强化者获得一个大小为10立方米的储物空间，从中拿取物品是一个迅捷动作。<br> 【能力解放】：当强化者使用盾牌时，若仅持有一面盾牌，则可以将除当前持有盾牌以外的一面自身已经购买且拥有的盾牌的基础属性（武器伤害、破防效果、附加成功、防御类型、格挡数值等）的一半与其上的特殊效果加至当前盾牌上。仅购买后经过了至少一次同级别战斗且在战斗中被使用的盾牌可被能力解放所影响。<br> 【等级提升】：强化者在赢得了同支线等级的战斗后，会提升一级勇者等级，每影片至多提升2次勇者等级。<br> 每一级勇者等级会提升人物的1点生命值上限与3点魔力值上限。</p><p>技能树</p><p>监牢之盾<br> 价格：C+1000<br> 动作：标准<br> 能耗：6点魔力<br> 射程：10米<br> 范围：目标点为圆心，半径5米的圆形<br> 目标：所有单位<br> 持续：三轮<br> 效果：进行一次攻击检定，目标以反射豁免，这次攻击不会造成伤害，若失败则会被周围升起的球状锁链所关押在区域内，这是一个C级别、变形来源的异空间效果。<br> 但与一般的异空间效果不同，任何单位都可以对这一球状空间进行攻击，其防御等同于使用者的格挡防御，结构值为使用者的沉着属性，当结构值被击破则异空间效果失效。若击破这一异空间的是范围攻击，还将继续对这次攻击射程内的单位造成影响。<br> 监牢之盾场上只会同时存在一个。</p><p>圣盾<br> 价格：C+1000<br> 需求：处于格挡状态<br> 动作：迅捷<br> 能耗：3点魔力<br> 射程：触及范围<br> 目标：所有友方单位<br> 持续：一轮<br> 效果：对处于范围内所有友方单位提供全遮蔽。<br> 增幅：可额外支付至多3魔力，每额外支付1点，该能力的范围就增加2米。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
